"use client";

import { useState, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  Share2,
  Volume2,
  RefreshCw,
  Quote,
  Check,
  Sparkles,
} from "lucide-react";
import { jokesData, type Language, type Joke } from "@/data/jokes";

/* ─── SVG Logo: Smiling Speech Bubble ─── */
const HasmukhLogo = ({ className = "w-10 h-10" }: { className?: string }) => (
  <svg
    viewBox="0 0 100 100"
    className={className}
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
  >
    <defs>
      <linearGradient id="logoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#FB923C" />
        <stop offset="50%" stopColor="#EC4899" />
        <stop offset="100%" stopColor="#F43F5E" />
      </linearGradient>
    </defs>
    <path
      d="M20 25C20 19.4772 24.4772 15 30 15H70C75.5228 15 80 19.4772 80 25V60C80 65.5228 75.5228 70 70 70H45L25 85V70H20C14.4772 70 10 65.5228 10 60V25C10 19.4772 14.4772 15 20 15Z"
      stroke="url(#logoGradient)"
      strokeWidth="5"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
    {/* Smile */}
    <path
      d="M35 45C35 45 42.5 55 50 55C57.5 55 65 45 65 45"
      stroke="url(#logoGradient)"
      strokeWidth="5"
      strokeLinecap="round"
    />
    {/* Eyes */}
    <circle cx="38" cy="36" r="3" fill="url(#logoGradient)" />
    <circle cx="62" cy="36" r="3" fill="url(#logoGradient)" />
  </svg>
);

/* ─── Font family helper ─── */
function getFontFamily(lang: Language): string {
  switch (lang) {
    case "ta":
      return "var(--font-noto-sans-tamil), sans-serif";
    case "te":
      return "var(--font-noto-sans-telugu), sans-serif";
    case "ml":
      return "var(--font-noto-sans-malayalam), sans-serif";
    case "hi":
    case "mr":
      return "var(--font-noto-sans-devanagari), sans-serif";
    default:
      return "var(--font-poppins), sans-serif";
  }
}

/* ─── Language Config ─── */
const languages: { code: Language; label: string }[] = [
  { code: "en", label: "English" },
  { code: "hi", label: "हिंदी" },
  { code: "mr", label: "मराठी" },
  { code: "ta", label: "தமிழ்" },
  { code: "te", label: "తెలుగు" },
  { code: "ml", label: "മലയാളം" },
];

/* ─── Main Component ─── */
export default function Home() {
  const [lang, setLang] = useState<Language>("en");
  const [currentJoke, setCurrentJoke] = useState<Joke>(jokesData.en[0]);
  const [isLoading, setIsLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  const getRandomJoke = useCallback(
    async (targetLang: Language) => {
      setIsLoading(true);
      let apiSuccess = false;

      // 1. Try external API
      try {
        const response = await fetch(
          `https://v2.jokeapi.dev/joke/Any?type=single&safe-mode&lang=${targetLang}`
        );
        const data = await response.json();
        if (!response.ok || data.error || !data.joke) {
          throw new Error("API unavailable");
        }
        setCurrentJoke({ id: data.id, text: data.joke });
        apiSuccess = true;
      } catch {
        console.warn("External API unavailable. Falling back to local data.");
      }

      // 2. Fallback to local jokes
      if (!apiSuccess) {
        const pool = jokesData[targetLang];
        if (pool && pool.length > 0) {
          let newJoke: Joke;
          do {
            newJoke = pool[Math.floor(Math.random() * pool.length)];
          } while (
            pool.length > 1 &&
            newJoke.id === currentJoke.id &&
            lang === targetLang
          );
          setCurrentJoke(newJoke);
        } else {
          setCurrentJoke({ id: 0, text: "No jokes found for this language." });
        }
      }

      setIsLoading(false);
    },
    [currentJoke.id, lang]
  );

  useEffect(() => {
    getRandomJoke(lang);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [lang]);

  /* ─── Share / Copy ─── */
  const handleShare = async () => {
    const text = `${currentJoke.text}\n\n— Hasmukh App`;
    if (navigator.share) {
      try {
        await navigator.share({
          title: "Hasmukh – Daily Dose of Laughter",
          text,
          url: window.location.href,
        });
      } catch {
        /* user cancelled */
      }
    } else {
      try {
        await navigator.clipboard.writeText(text);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      } catch {
        /* clipboard denied */
      }
    }
  };

  /* ─── Speech Synthesis ─── */
  const speakJoke = () => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(currentJoke.text);
    const langMap: Record<Language, string> = {
      en: "en-US",
      hi: "hi-IN",
      mr: "mr-IN",
      ta: "ta-IN",
      te: "te-IN",
      ml: "ml-IN",
    };
    utterance.lang = langMap[lang];
    window.speechSynthesis.speak(utterance);
  };

  return (
    <main
      style={{ minHeight: "100vh", background: "#030712" }}
      className="relative flex flex-col items-center overflow-hidden text-white"
    >
      {/* ═══ Atmospheric Aura ═══ */}
      <div className="aura-blob aura-blob--indigo" />
      <div className="aura-blob aura-blob--rose" />

      {/* ═══ Content Wrapper (z-10) ═══ */}
      <div
        className="relative flex flex-col items-center w-full flex-1"
        style={{ zIndex: 10, padding: "2rem clamp(1rem, 4vw, 3rem)" }}
      >
        {/* ─── Header ─── */}
        <header className="w-full max-w-7xl flex flex-col md:flex-row justify-between items-center gap-4">
          {/* Logo + Brand */}
          <motion.div
            initial={{ x: -20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ duration: 0.6, ease: "easeOut" }}
            className="flex items-center gap-3 group cursor-default select-none"
          >
            <div className="relative">
              <HasmukhLogo className="w-11 h-11 transition-transform duration-500 group-hover:rotate-12" />
              <Sparkles className="absolute -top-1 -right-1 w-3.5 h-3.5 text-orange-400 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
            </div>
            <h1
              className="text-brand-gradient font-black tracking-[0.2em]"
              style={{ fontSize: "1.5rem" }}
            >
              HASMUKH
            </h1>
          </motion.div>

          {/* Language Selector */}
          <motion.nav
            initial={{ x: 20, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            transition={{ duration: 0.6, ease: "easeOut", delay: 0.15 }}
            className="lang-bar flex gap-1 p-1"
          >
            {languages.map((l) => (
              <button
                key={l.code}
                id={`lang-${l.code}`}
                onClick={() => setLang(l.code)}
                className={`lang-pill ${
                  lang === l.code ? "lang-pill--active" : "lang-pill--inactive"
                }`}
              >
                {l.label}
              </button>
            ))}
          </motion.nav>
        </header>

        {/* ─── Joke Card (Centerpiece) ─── */}
        <div className="flex-1 w-full max-w-5xl flex items-center justify-center py-8 md:py-16">
          <motion.div
            initial={{ opacity: 0, scale: 0.96, y: 16 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            transition={{ duration: 0.7, ease: "easeOut", delay: 0.25 }}
            className="glass-card w-full relative overflow-hidden flex items-center justify-center"
            style={{
              borderRadius: "3rem",
              padding: "clamp(2.5rem, 5vw, 4rem) clamp(2rem, 4vw, 5rem)",
              minHeight: "340px",
            }}
          >
            {/* Quote accents */}
            <div className="quote-accent quote-accent--tl">
              <Quote size={44} className="fill-white" />
            </div>
            <div className="quote-accent quote-accent--br">
              <Quote size={44} className="fill-white" />
            </div>

            {/* Joke Text */}
            <div className="relative w-full" style={{ zIndex: 2 }}>
              <AnimatePresence mode="wait">
                <motion.div
                  key={`${currentJoke.id}-${lang}`}
                  initial={{ opacity: 0, y: 24 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -20 }}
                  transition={{ duration: 0.45, ease: [0.4, 0, 0.2, 1] }}
                  className="flex items-center justify-center"
                >
                  <p
                    className={
                      lang === "en" ? "joke-text-en" : "joke-text-regional"
                    }
                    style={{
                      fontFamily: getFontFamily(lang),
                      textAlign: "center",
                      color: "rgba(255,255,255,0.92)",
                      maxWidth: "52ch",
                    }}
                  >
                    {currentJoke.text}
                  </p>
                </motion.div>
              </AnimatePresence>
            </div>
          </motion.div>
        </div>

        {/* ─── Action Dock ─── */}
        <footer className="w-full flex flex-col items-center gap-8 pb-4">
          <motion.div
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ duration: 0.6, ease: "easeOut", delay: 0.4 }}
            className="dock-bar flex items-center gap-3"
          >
            {/* Next Laugh Button */}
            <motion.button
              id="next-laugh-btn"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => getRandomJoke(lang)}
              disabled={isLoading}
              className="bg-brand-gradient btn-glow flex items-center gap-2.5 rounded-full text-white font-bold disabled:opacity-50"
              style={{
                padding: "0.875rem 2.5rem",
                fontSize: "0.9375rem",
                letterSpacing: "0.02em",
              }}
            >
              <RefreshCw
                size={20}
                className={`transition-transform duration-500 ${
                  isLoading ? "animate-spin" : ""
                }`}
              />
              <span>Next Laugh</span>
            </motion.button>

            {/* Icon Controls */}
            <div className="flex items-center gap-2.5">
              <motion.button
                id="speak-btn"
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={speakJoke}
                className="icon-btn"
                aria-label="Listen to joke"
              >
                <Volume2 size={20} />
              </motion.button>

              <div className="relative">
                <motion.button
                  id="share-btn"
                  whileHover={{ scale: 1.1 }}
                  whileTap={{ scale: 0.9 }}
                  onClick={handleShare}
                  className="icon-btn"
                  aria-label="Share joke"
                >
                  {copied ? (
                    <Check size={20} className="text-emerald-400" />
                  ) : (
                    <Share2 size={20} />
                  )}
                </motion.button>

                {/* Copied tooltip */}
                <AnimatePresence>
                  {copied && (
                    <motion.span
                      initial={{ opacity: 0, y: 6, scale: 0.9 }}
                      animate={{ opacity: 1, y: 0, scale: 1 }}
                      exit={{ opacity: 0, y: 4, scale: 0.9 }}
                      transition={{ duration: 0.2 }}
                      className="tooltip-copied"
                    >
                      COPIED!
                    </motion.span>
                  )}
                </AnimatePresence>
              </div>
            </div>
          </motion.div>

          {/* Footer branding */}
          <div className="flex flex-col items-center gap-2">
            <p className="footer-text">
              © {new Date().getFullYear()} HASMUKH • PURE LAUGHTER
            </p>
            <div className="footer-bar bg-brand-gradient" />
          </div>
        </footer>
      </div>
    </main>
  );
}
